// Responsive Header
// Custom attributes: data-jf-collapse ("always"|"never"), data-jf-order-desktop (int), data-jf-order-mobile (int)
(function(){var b=800,p=!1,lc=0,lm=null,rt=null;function is(){if(document.getElementById('jf-resp-header-css'))return;var s=document.createElement('style');s.id='jf-resp-header-css';s.innerHTML='.headerRight { display: flex !important; } #jf-more-wrap { position: relative; display: flex; align-items: center; margin-left: 5px; z-index: 99999; order: 9999; } #jf-more-btn { background: transparent; border: none; color: inherit; cursor: pointer; padding: 8px; border-radius: 50%; display: flex; align-items: center; justify-content: center; transition: background 0.2s; outline: none; } #jf-more-btn:hover { background: rgba(255,255,255,0.1); } #jf-more-menu { position: fixed; top: 70px; right: 15px; background: var(--lighterGradientPoint, var(--theme-background, #1a1a1a)); border: 1px solid rgba(255,255,255,0.1); border-radius: 8px; padding: 8px; display: flex; flex-direction: column; gap: 4px; box-shadow: 0 10px 30px rgba(0,0,0,0.8); opacity: 0; pointer-events: none; transform: translateY(-10px); transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1); min-width: 220px; backdrop-filter: blur(10px); z-index: 999999 !important; max-height: calc(100vh - 90px); overflow-y: auto; overflow-x: hidden; } #jf-more-menu.open { opacity: 1; pointer-events: auto; transform: translateY(0); } #jf-more-menu::-webkit-scrollbar { width: 6px; } #jf-more-menu::-webkit-scrollbar-thumb { background: #444; border-radius: 3px; } #jf-more-menu > * { display: flex !important; align-items: center !important; height: 48px !important; width: 100%; justify-content: flex-start !important; padding: 0 15px !important; margin: 0 !important; border-radius: 6px; box-sizing: border-box; flex-shrink: 0; } #jf-more-menu > *:hover { background: rgba(255,255,255,0.08); } #jf-more-menu .material-icons { margin-right: 15px; font-size: 1.3rem; } #jf-more-menu > .hide { display: none !important; } #jf-more-menu > .headerSelectedPlayer:empty { display: none !important; } #jf-more-menu .headerButton::after { content: attr(title); font-family: sans-serif; font-size: 1rem; font-weight: 500; white-space: nowrap; } #jf-more-menu #jf-header-ping { background: transparent; border: none; } #jf-more-menu .headerButton > img, #jf-more-menu .headerButton > .headerUserButtonRound { width: 24px !important; height: 24px !important; margin: 0 15px 0 0 !important; border-radius: 50% !important; object-fit: cover !important; flex-shrink: 0 !important; }';document.head.appendChild(s);document.addEventListener('click',function(e){var btn=document.getElementById('jf-more-btn'),m=document.getElementById('jf-more-menu');if(btn&&m&&m.classList.contains('open')&&!m.contains(e.target)&&!btn.contains(e.target))m.classList.remove('open');});}function mrh(){if(p)return;var hr=document.querySelector('.headerRight')||document.querySelector('.mainHeader .flex-direction-row');if(!hr)return;var im=window.innerWidth<=b,m=document.getElementById('jf-more-menu'),w=document.getElementById('jf-more-wrap'),cc=hr.children.length+(m?m.children.length:0);if(w&&lm===im&&lc===cc)return;p=!0;if(!w){w=document.createElement('div');w.id='jf-more-wrap';w.innerHTML='<button id="jf-more-btn" class="material-icons">more_vert</button>';hr.appendChild(w);m=document.createElement('div');m.id='jf-more-menu';document.body.appendChild(m);document.getElementById('jf-more-btn').addEventListener('click',function(e){e.stopPropagation();m.classList.toggle('open');});}var c=[].slice.call(hr.children),mc=[].slice.call(m.children);function dsc(el){return el.id!=='jf-more-wrap'&&el.id!=='jrpg-badge-wrap'&&el.id!=='rpg-nav-btn'&&(!el.classList||!el.classList.contains('headerSearchButton'))&&(el.matches&&el.matches('.headerButton, #jf-header-ping, .headerSelectedPlayer'));}for(var i=0;i<c.length;i++){var el=c[i];if(el.id==='jf-more-wrap')continue;var ca=el.getAttribute('data-jf-collapse'),sbm=ca==='always'||(ca!=='never'&&im&&dsc(el));if(sbm&&el.parentNode!==m)m.appendChild(el);}for(var j=0;j<mc.length;j++){var mel=mc[j],ca=mel.getAttribute('data-jf-collapse'),sbm=ca==='always'||(ca!=='never'&&im&&dsc(mel));if(!sbm&&mel.parentNode!==hr)hr.insertBefore(mel,w);}var ae=[].slice.call(hr.children).concat([].slice.call(m.children));for(var k=0;k<ae.length;k++){var n=ae[k];if(n.id==='jf-more-wrap')continue;var inM=n.parentNode===m,od=n.getAttribute('data-jf-order-desktop'),om=n.getAttribute('data-jf-order-mobile');if(inM&&om!==null)n.style.order=om;else if(!inM&&od!==null)n.style.order=od;else n.style.order='';}if(m.children.length===0){w.style.display='none';m.classList.remove('open');}else{w.style.display='flex';}if(lm!==null&&lm!==im)m.classList.remove('open');lm=im;lc=hr.children.length+m.children.length;p=!1;}is();setInterval(mrh,1000);window.addEventListener('resize',function(){if(rt)clearTimeout(rt);rt=setTimeout(mrh,100);});})();
